import os
from cryptography.fernet import Fernet

def generate_key():
    return Fernet.generate_key()

def load_key(key_path):
    with open(key_path, 'rb') as file:
        return file.read()

def save_key(key, key_path):
    with open(key_path, 'wb') as file:
        file.write(key)

def encrypt_credit_card(credit_card_number, key):
    fernet = Fernet(key)
    encrypted_credit_card = fernet.encrypt(credit_card_number.encode())
    return encrypted_credit_card

def decrypt_credit_card(encrypted_credit_card, key):
    fernet = Fernet(key)
    decrypted_credit_card = fernet.decrypt(encrypted_credit_card).decode()
    return decrypted_credit_card

# Example usage
if __name__ == "__main__":
    # Path to store the encryption key
    key_path = 'encryption_key.key'

    # Generate and save a new key if it doesn't exist
    if not os.path.exists(key_path):
        key = generate_key()
        save_key(key, key_path)
    else:
        key = load_key(key_path)

    credit_card_number = "4111111111111111"

    # Encrypt the credit card number
    encrypted_credit_card = encrypt_credit_card(credit_card_number, key)
    print(f"Encrypted Credit Card: {encrypted_credit_card}")

    # Decrypt the credit card number
    decrypted_credit_card = decrypt_credit_card(encrypted_credit_card, key)
    print(f"Decrypted Credit Card: {decrypted_credit_card}")